    let cli = Cli::try_parse_from(["test", "--scope", "code"]).unwrap();
    assert_eq!(cli.args.scope, Some(Scope(vec![Side::Code])));
}

/// `--scope=code,bot` parses into `Scope([Code, Bot])`.
#[test]
fn parse_scope_code_bot() {
